#include <bits/stdc++.h>
using namespace std;

int main() {
    string a, b;
    getline(cin, a);
    getline(cin, b);

    int res = 0, p = 0, c = 0, f = 0;
    int a_len = a.length();

    // Parsing first string 'a'
    for (int i = 0; i < a_len; i++) {
        if (a[i] == ' ') continue;
        if (isdigit(a[i])) {
            res = res * 10 + a[i] - '0';
        } else {
            if (a[i] == 'P') p = res;
            else if (a[i] == 'C') c = res;
            else f = res;
            res = 0;
        }
    }

    int pp = 0, cc = 0, ff = 0;
    vector<vector<int>> ans;
    res = 0;
    int mi = INT_MAX, sump = 0, sumc = 0, sumf = 0;
    int b_len = b.length();

    // Parsing second string 'b'
    for (int i = 0; i < b_len; i++) {
        if (b[i] == ' ') continue;
        if (b[i] == '|') {
            ans.push_back({pp, cc, ff});
            pp = 0; cc = 0; ff = 0;
        } else if (isdigit(b[i])) {
            res = res * 10 + b[i] - '0';
        } else {
            if (b[i] == 'P') {
                pp = res;
                sump += pp;
            } else if (b[i] == 'C') {
                cc = res;
                sumc += cc;
            } else {
                ff = res;
                sumf += ff;
            }
            res = 0;
        }
    }
    ans.push_back({pp, cc, ff});

    if (sump > 0) mi = min(mi, p / sump);
    if (sumc > 0) mi = min(mi, c / sumc);
    if (sumf > 0) mi = min(mi, f / sumf);
    if (mi == INT_MAX) mi = 0;

    vector<int> lef = {p - mi * sump, c - mi * sumc, f - mi * sumf};
    vector<int> ma = {0, 0, 0};
    vector<int> curr(3);
    int nn = ans.size();

    // Evaluating all subsets
    for (int i = 0; i < (1 << nn); i++) {
        fill(curr.begin(), curr.end(), 0);
        for (int j = 0; j < nn; j++) {
            if ((i & (1 << j)) != 0) {
                curr[0] += ans[j][0];
                curr[1] += ans[j][1];
                curr[2] += ans[j][2];
            }
        }
        if (curr[0] <= lef[0] && curr[1] <= lef[1] && curr[2] <= lef[2]) {
            if (curr[0] > ma[0] || (curr[0] == ma[0] && curr[1] > ma[1]) || 
                (curr[0] == ma[0] && curr[1] == ma[1] && curr[2] > ma[2])) {
                ma = curr;
            }
        }
    }

    cout << (p - sump * mi - ma[0]) << " " << (c - sumc * mi - ma[1]) << " " << (f - sumf * mi - ma[2]);

    return 0;
}

