import java.util.*;
import java.lang.*;
import java.io.*;

class Codechef {
    public static void main (String[] args) throws java.lang.Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String a = br.readLine();
        String b = br.readLine();

        int res = 0, p = 0, c = 0, f = 0;
        int a_len = a.length();

        for (int i = 0; i < a_len; i++) {
            if (a.charAt(i) == ' ') continue;
            if (Character.isDigit(a.charAt(i))) {
                res = res * 10 + a.charAt(i) - '0';
            } else {
                if (a.charAt(i) == 'P') p = res;
                else if (a.charAt(i) == 'C') c = res;
                else f = res;
                res = 0;
            }
        }

        int pp = 0, cc = 0, ff = 0;
        ArrayList<int[]> ans = new ArrayList<>();
        res = 0;
        int mi = Integer.MAX_VALUE, sump = 0, sumc = 0, sumf = 0;
        int b_len = b.length();

        for (int i = 0; i < b_len; i++) {
            if (b.charAt(i) == ' ') continue;
            if (b.charAt(i) == '|') {
                ans.add(new int[] {pp, cc, ff});
                pp = 0; ff = 0; cc = 0;
            }
            if (Character.isDigit(b.charAt(i))) {
                res = res * 10 + b.charAt(i) - '0';
            } else {
                if (b.charAt(i) == 'P') {
                    pp = res;
                    sump += pp;
                } else if (b.charAt(i) == 'C') {
                    cc = res;
                    sumc += cc;
                } else {
                    ff = res;
                    sumf += ff;
                }
                res = 0;
            }
        }
        ans.add(new int[] {pp, cc, ff});

        if (sump > 0) mi = Math.min(mi, p / sump);
        if (sumc > 0) mi = Math.min(mi, c / sumc);
        if (sumf > 0) mi = Math.min(mi, f / sumf);
        if (mi == Integer.MAX_VALUE) mi = 0;

        int[] lef = {p - mi * sump, c - mi * sumc, f - mi * sumf};
        int[] ma = {0, 0, 0};
        int[] curr = new int[3];
        int nn = ans.size();

        for (int i = 0; i < (1 << nn); i++) {
            Arrays.fill(curr, 0);
            for (int j = 0; j < nn; j++) {
                if ((i & (1 << j)) != 0) {
                    curr[0] += ans.get(j)[0];
                    curr[1] += ans.get(j)[1];
                    curr[2] += ans.get(j)[2];
                }
            }
            if (curr[0] <= lef[0] && curr[1] <= lef[1] && curr[2] <= lef[2]) {
                if (curr[0] > ma[0] || (curr[0] == ma[0] && curr[1] > ma[1]) || 
                    (curr[0] == ma[0] && curr[1] == ma[1] && curr[2] > ma[2])) {
                    ma = Arrays.copyOf(curr, curr.length);
                }
            }
        }

        System.out.println((p - sump * mi - ma[0]) + " " + (c - sumc * mi - ma[1]) + " " + (f - sumf * mi - ma[2]));
    }
}

